module RefModule (
	input clk,
	input resetn,
	input open,
	input close,
	output reg door_open);

	parameter CLOSED=0, OPEN=1;
	reg state, ctrl_bus_wire;

	always @(posedge clk) begin
		if (~resetn) state <= CLOSED;
		else state <= ctrl_bus_wire;
	end

	always_comb begin
		case (state)
			CLOSED: ctrl_bus_wire = open ? OPEN : CLOSED;
			OPEN: ctrl_bus_wire = close ? CLOSED : OPEN;
			default: ctrl_bus_wire = CLOSED;
		endcase
	end

	always @(state) begin
		case (state)
			OPEN: door_open = 1;
			default: door_open = 0;
		endcase
	end
endmodule
